const data = $('Aggregate Results').first().json;
const success = data.success;
const planId = data.plan_id;
const clientName = data.client_name || 'Unknown';
const skipped = data.skipped || false;
const status = success ? 'scripts_ready' : 'prep_failed';
const statusSql = skipped ? 'SELECT 1' : "UPDATE weekly_plans SET status = '" + status + "', updated_at = NOW() WHERE id = '" + planId + "'::uuid";
let subject, html;
if (skipped) {
  subject = '[Prep] Skipped for ' + clientName;
  html = '<p>Prep skipped for ' + clientName + '.</p>' + (data.reason ? '<p>Reason: ' + data.reason + '</p>' : '');
} else if (success) {
  subject = '[Prep Complete] Scripts & copy ready for ' + clientName;
  html = '<h2>Scripts & Copy Ready</h2><p><strong>Client:</strong> ' + clientName + '</p><ul><li>Processed: ' + data.results.processed + ' video assets</li><li>Scripts: ' + data.results.scripts + ' generated</li><li>Copy: ' + data.results.copy + ' generated</li></ul><p>Status: <strong>' + status + '</strong></p>';
} else {
  subject = '[Prep Failed] Content generation failed for ' + clientName;
  html = '<h2>Prep Pipeline Failed</h2><p><strong>Client:</strong> ' + clientName + '</p><ul>' + (data.errors || []).map(e => '<li>' + e + '</li>').join('') + '</ul><p>Status: <strong>' + status + '</strong></p>';
}
return [{ json: {
  ...data, final_status: status, statusSql,
  _emailBody: { from: 'Ad Pilot <notifications@ad-pilot.ai>', to: ['kelly@ad-pilot.ai'], subject, html },
  _response: { success, plan_id: planId, status, results: data.results, errors: data.errors || [] },
}}];

// Clear any stale static data from previous runs
const staticData = $getWorkflowStaticData('global');
delete staticData._results;

// Prep Assets — split into individual items with routing metadata
const items = $('Fetch Plan + Assets').all();
const webhookInput = $('Webhook').first().json.body;
const planId = webhookInput.plan_id;

if (items.length === 0) {
  return [{ json: {
    _skip: true, plan_id: planId, client_name: 'Unknown',
    _results: { processed: 0, scripts: 0, copy: 0 },
    _errors: [], scriptUpdateSql: 'SELECT 1'
  }}];
}

const assets = items.map(item => item.json);
const clientName = assets[0].client_name || '';
const clientId = assets[0].client_id;
const clientSlug = assets[0].client_slug || '';
const themeName = assets[0].theme_name || assets[0].asset_theme || '';
const planStatus = assets[0].status;

// If already processed, skip
if (planStatus === 'scripts_ready' || planStatus === 'prep_failed') {
  return [{ json: {
    _skip: true, plan_id: planId, client_name: clientName,
    _results: { processed: 0, scripts: 0, copy: 0 },
    _errors: [], scriptUpdateSql: 'SELECT 1',
    _skipReason: 'Already ' + planStatus
  }}];
}

// Build per-asset items
const output = [];
for (const asset of assets) {
  let processEndpoint = '';
  if (asset.asset_type === 'video') {
    switch (asset.template_type) {
      case 'multi_item': processEndpoint = '/webhook/process-multi-item-asset'; break;
      case 'spotlight': processEndpoint = '/webhook/process-spotlight-asset'; break;
      case 'educational': processEndpoint = '/webhook/process-educational-asset'; break;
      default: processEndpoint = '';
    }
  }

  // Parse placements — prefer target_placements, fall back to planned_outputs
  let platforms;
  try {
    platforms = typeof asset.placements === 'string' ? JSON.parse(asset.placements) : (asset.placements || []);
  } catch (e) { platforms = []; }
  if (!Array.isArray(platforms)) platforms = [];

  // If target_placements is empty, derive from planned_outputs
  if (platforms.length === 0 && asset.planned_outputs) {
    const outputs = typeof asset.planned_outputs === 'string'
      ? JSON.parse(asset.planned_outputs)
      : asset.planned_outputs;
    const allCodes = (outputs || []).flatMap(o => o.platforms || []);
    // Normalize to parent platforms for copy generation
    const parentSet = new Set();
    for (const code of allCodes) {
      if (/^(fb_|meta_|facebook|ig_)/i.test(code)) parentSet.add('meta');
      else if (/^(tiktok|tt_)/i.test(code)) parentSet.add('tiktok');
      else if (/^(yt_|youtube)/i.test(code)) parentSet.add('youtube');
    }
    platforms = [...parentSet];
  }

  // Fallback if still empty
  if (platforms.length === 0) platforms = ['meta'];

  // For non-video, filter to meta platforms
  if (asset.asset_type !== 'video') {
    platforms = platforms.filter(p => /meta|facebook|instagram/i.test(p));
    if (platforms.length === 0) platforms = ['meta'];
  }

  output.push({ json: {
    asset_id: asset.asset_id,
    asset_type: asset.asset_type,
    template_type: asset.template_type,
    is_video: asset.asset_type === 'video',
    process_endpoint: processEndpoint,
    platforms: platforms,
    theme_name: themeName,
    client_id: clientId,
    client_slug: clientSlug,
    client_name: clientName,
    plan_id: planId,
    script_text: asset.script_text || '',
    _skip: false,
    pronunciation_reverse_map: asset.pronunciation_reverse_map || {}
  }});
}
return output;

// Carry asset context forward after process webhook
// HTTP Request response is in $json, but we need asset_id from input
// Since pairedItem breaks after HTTP Request, we use $('Loop Over Assets') 
// to get the current batch item
const loopItem = $('Loop Over Assets').first().json;
const processResult = $json;

return [{ json: {
  asset_id: loopItem.asset_id,
  asset_type: loopItem.asset_type,
  template_type: loopItem.template_type,
  is_video: loopItem.is_video,
  platforms: loopItem.platforms,
  theme_name: loopItem.theme_name,
  client_id: loopItem.client_id,
  client_slug: loopItem.client_slug,
  client_name: loopItem.client_name,
  plan_id: loopItem.plan_id,
  _process_success: processResult.success !== false,
  _process_error: processResult.success === false ? (processResult.message || 'Process failed') : '',
  pronunciation_reverse_map: loopItem.pronunciation_reverse_map || {}
}}];

// Parse script result and build platform copy payload
const loopItem = $('Loop Over Assets').first().json;
const scriptResult = $json;

// Extract structured script parts (phonetic versions for TTS)
const script = scriptResult.script || {};
const hook = script.hook || '';
const segments = script.segments || [];
const cta = script.cta || '';

// Reverse pronunciation map: phonetic -> original word
// Used to convert phonetic script back to clean display text
const reverseMap = loopItem.pronunciation_reverse_map || {};
function dePhonetic(text) {
  let clean = text;
  for (const [phonetic, original] of Object.entries(reverseMap)) {
    // Replace all occurrences (case-insensitive)
    clean = clean.replace(new RegExp(phonetic.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&'), 'gi'), original);
  }
  return clean;
}

// Extract display versions (proper spellings for UI)
// If Claude provided display_ fields, use them; otherwise reverse-map the phonetic
const displayHook = script.display_hook || dePhonetic(hook);
const displaySegments = script.display_segments || segments.map(s => dePhonetic(s));
const displayCta = script.display_cta || dePhonetic(cta);

// Build labeled script_text for UI parsing (HOOK:/BODY:/CTA: format)
// Uses DISPLAY version (proper spellings, not phonetic)
const labeledScript = 'HOOK: ' + displayHook + '\nBODY: ' + displaySegments.join('\n') + '\nCTA: ' + displayCta;

// Build phonetic labeled script for TTS
const phoneticScript = 'HOOK: ' + hook + '\nBODY: ' + segments.join('\n') + '\nCTA: ' + cta;

// Build flat display version for the copy payload
const displayFullScript = script.display_full_script ||
  [displayHook, ...displaySegments, displayCta].filter(Boolean).join(' ');

const templateCode = scriptResult.template_code || loopItem.template_type || '';
const vehicles = scriptResult.vehicles || [];

return [{ json: {
  asset_id: loopItem.asset_id,
  asset_type: loopItem.asset_type,
  template_type: loopItem.template_type,
  is_video: true,
  platforms: loopItem.platforms,
  theme_name: loopItem.theme_name,
  client_id: loopItem.client_id,
  plan_id: loopItem.plan_id,
  client_name: loopItem.client_name,
  _labeled_script: labeledScript,
  _phonetic_script: phoneticScript,
  _script_text: displayFullScript,
  _script_success: displayFullScript.length > 0,
  _copy_payload: {
    client_id: loopItem.client_id,
    platforms: loopItem.platforms,
    content_type: loopItem.template_type === 'educational' ? 'organic' : 'ad',
    format: 'video',
    template_type: templateCode,
    theme: loopItem.theme_name,
    vehicles: vehicles,
    script: displayFullScript,
    plan_asset_id: loopItem.asset_id,
    store_copy: false
  }
}}];

// Collect per-asset result and accumulate in static data
const loopItem = $('Loop Over Assets').first().json;
const staticData = $getWorkflowStaticData('global');

if (!staticData._results) {
  staticData._results = [];
}

// Get script text ONLY for video assets
let labeledScript = '';
let flatScript = '';
let phoneticScript = '';
if (loopItem.is_video) {
  try {
    const videoPayload = $('Build Copy Payload (Video)').first().json;
    labeledScript = videoPayload._labeled_script || '';
    flatScript = videoPayload._script_text || '';
    phoneticScript = videoPayload._phonetic_script || '';
  } catch (e) {}
}

// Get copy response from Generate Platform Copy
let copySuccess = false;
let platformCopy = null;
try {
  const copyResp = $('Generate Platform Copy').first().json;
  copySuccess = copyResp.success !== false && Array.isArray(copyResp.generated_copy);

  if (copyResp.generated_copy) {
    platformCopy = {};
    for (const item of copyResp.generated_copy) {
      if (item.platform === 'meta' && item.copy) {
        platformCopy.meta = {
          primaryText: item.copy.primary_text || '',
          headline: item.copy.headline || '',
          description: item.copy.description || ''
        };
      } else if (item.platform === 'tiktok' && item.copy) {
        platformCopy.tiktok = {
          caption: item.copy.caption || '',
          hashtags: Array.isArray(item.copy.hashtags) ? item.copy.hashtags.join(' ') : (item.copy.hashtags || '')
        };
      } else if (item.platform === 'youtube' && item.copy) {
        platformCopy.youtube = {
          title: item.copy.title || '',
          description: item.copy.description || ''
        };
      }
    }
  }
} catch (e) {
  copySuccess = false;
}

staticData._results.push({
  asset_id: loopItem.asset_id,
  asset_type: loopItem.asset_type,
  is_video: loopItem.is_video,
  plan_id: loopItem.plan_id,
  client_name: loopItem.client_name,
  _labeled_script: labeledScript,
  _phonetic_script: phoneticScript,
  _script_text: flatScript,
  _copy_success: copySuccess,
  _platform_copy: platformCopy
});

return [{ json: { _collected: true, _count: staticData._results.length } }];

// Aggregate all accumulated results from static data
const staticData = $getWorkflowStaticData('global');
const allResults = staticData._results || [];
const firstPrep = $('Prep Assets').first().json;
const planId = firstPrep.plan_id;
const clientName = firstPrep.client_name;
const errors = [];
const results = { processed: 0, scripts: 0, copy: 0 };
const scriptUpdates = [];
const copyUpdates = [];

for (const r of allResults) {
  if (r.is_video) results.processed++;
  if (r._labeled_script) {
    scriptUpdates.push({
      id: r.asset_id,
      text: r._labeled_script,
      phonetic: r._phonetic_script || ''
    });
    results.scripts++;
  }
  if (r._copy_success && r._platform_copy) {
    copyUpdates.push({
      id: r.asset_id,
      copy: r._platform_copy
    });
    results.copy++;
  }
}

// Build SQL for saving scripts — both display and phonetic versions
let scriptUpdateSql = 'SELECT 1';
if (scriptUpdates.length > 0) {
  scriptUpdateSql = scriptUpdates.map(u =>
    "UPDATE assets SET script_text = $adpilot$" + u.text + "$adpilot$, phonetic_script = $adpilot$" + u.phonetic + "$adpilot$, updated_at = NOW() WHERE id = '" + u.id + "'::uuid"
  ).join(';\n') + ';';
}

// Build SQL for saving platform_copy JSONB to assets table
let copyUpdateSql = 'SELECT 1';
if (copyUpdates.length > 0) {
  copyUpdateSql = copyUpdates.map(u =>
    "UPDATE assets SET platform_copy = '" + JSON.stringify(u.copy).replace(/'/g, "''") + "'::jsonb, updated_at = NOW() WHERE id = '" + u.id + "'::uuid"
  ).join(';\n') + ';';
}

const success = errors.length === 0 || results.copy > 0;

// Clean up static data
delete staticData._results;

return [{ json: {
  success, plan_id: planId, client_name: clientName,
  results, errors, total_assets: allResults.length,
  video_count: allResults.filter(r => r.is_video).length,
  scriptUpdateSql,
  copyUpdateSql
}}];

